from collections import defaultdict

class Solution:
    def groupAnagrams(self, strs: list[str]) -> list[list[str]]:
        bucket: dict[str, list[str]] = defaultdict(list)
        for s in strs:
            bucket["".join(sorted(s))].append(s)
        return list(bucket.values())

