from collections import defaultdict   # 访问不存在的 key 时自动给默认值

class Solution:
    def groupAnagrams(self, strs: list[str]) -> list[list[str]]:
        bucket: dict[tuple, list[str]] = defaultdict(list)  # key 不存在时默认空列表 []
        for s in strs:
            cnt = [0] * 26                 # 26 个字母的计数桶
            for c in s:
                cnt[ord(c) - 97] += 1      # ord('a')=97,所以 'a'->0,'b'->1 ...
            bucket[tuple(cnt)].append(s)   # 用「计数」当 key:计数相同 -> 同一组
        return list(bucket.values())       # 取出所有分组
